DECLARE
  i NUMBER := 1;
BEGIN
  LOOP
    DBMS_OUTPUT.PUT_LINE(i);
    EXIT WHEN i >= 5;
    i := i + 1;
  END LOOP;
END;

DECLARE
  i NUMBER := 10;
BEGIN
  LOOP
    DBMS_OUTPUT.PUT_LINE(i);
    EXIT WHEN i <= 1;
    i := i - 1;
  END LOOP;
END;

DECLARE
  i NUMBER := 1;
  s NUMBER := 0;
BEGIN
  LOOP
    s := s + i;
    EXIT WHEN i >= 10;
    i := i + 1;
  END LOOP;
  DBMS_OUTPUT.PUT_LINE('Sum: ' || s);
END;

DECLARE
  n NUMBER := 2;
  i NUMBER := 1;
BEGIN
  LOOP
    DBMS_OUTPUT.PUT_LINE(n || ' * ' || i || ' = ' || (n * i));
    EXIT WHEN i >= 10;
    i := i + 1;
  END LOOP;
END;

DECLARE
  i NUMBER := 2;
BEGIN
  LOOP
    DBMS_OUTPUT.PUT_LINE(i);
    EXIT WHEN i >= 20;
    i := i + 2;
  END LOOP;
END;

DECLARE
  i NUMBER := 45;
BEGIN
  LOOP
    DBMS_OUTPUT.PUT_LINE(i);
    EXIT WHEN i >= 50;
    i := i + 1;
  END LOOP;
END;

DECLARE
  i NUMBER := 1;
BEGIN
  WHILE i <= 10 LOOP
    DBMS_OUTPUT.PUT_LINE(i);
    i := i + 1;
  END LOOP;
END;

DECLARE
  n NUMBER := 5;
  f NUMBER := 1;
BEGIN
  WHILE n > 0 LOOP
    f := f * n;
    n := n - 1;
  END LOOP;
  DBMS_OUTPUT.PUT_LINE('Factorial: ' || f);
END;

DECLARE
  n NUMBER := 123;
  s NUMBER := 0;
BEGIN
  WHILE n > 0 LOOP
    s := s + MOD(n, 10);
    n := TRUNC(n / 10);
  END LOOP;
  DBMS_OUTPUT.PUT_LINE('Sum: ' || s);
END;

DECLARE
  n NUMBER := 123;
  r NUMBER := 0;
BEGIN
  WHILE n > 0 LOOP
    r := (r * 10) + MOD(n, 10);
    n := TRUNC(n / 10);
  END LOOP;
  DBMS_OUTPUT.PUT_LINE('Reversed: ' || r);
END;

DECLARE
  n NUMBER := 121;
  r NUMBER := 0;
  temp NUMBER;
BEGIN
  temp := n;
  WHILE n > 0 LOOP
    r := (r * 10) + MOD(n, 10);
    n := TRUNC(n / 10);
  END LOOP;
  IF temp = r THEN
    DBMS_OUTPUT.PUT_LINE('Palindrome');
  END IF;
END;

DECLARE
  a NUMBER := 0;
  b NUMBER := 1;
  c NUMBER;
  i NUMBER := 1;
BEGIN
  WHILE i <= 5 LOOP
    DBMS_OUTPUT.PUT_LINE(a);
    c := a + b;
    a := b;
    b := c;
    i := i + 1;
  END LOOP;
END;

BEGIN
  FOR i IN 1..10 LOOP
    DBMS_OUTPUT.PUT_LINE(i);
  END LOOP;
END;

BEGIN
  FOR i IN REVERSE 1..5 LOOP
    DBMS_OUTPUT.PUT_LINE(i);
  END LOOP;
END;

DECLARE
  s NUMBER := 0;
BEGIN
  FOR i IN 1..10 LOOP
    s := s + i;
  END LOOP;
  DBMS_OUTPUT.PUT_LINE(s);
END;

BEGIN
  FOR i IN 1..10 LOOP
    DBMS_OUTPUT.PUT_LINE('5 * ' || i || ' = ' || (5 * i));
  END LOOP;
END;

BEGIN
  FOR i IN 1..10 LOOP
    DBMS_OUTPUT.PUT_LINE(i * i);
  END LOOP;
END;

BEGIN
  FOR i IN 1..20 LOOP
    IF MOD(i, 2) != 0 THEN
      DBMS_OUTPUT.PUT_LINE(i);
    END IF;
  END LOOP;
END;

DECLARE
  v_star VARCHAR2(10) := '';
BEGIN
  FOR i IN 1..4 LOOP
    v_star := v_star || '*';
    DBMS_OUTPUT.PUT_LINE(v_star);
  END LOOP;
END;

BEGIN
  FOR i IN 1..3 LOOP
    FOR j IN 1..5 LOOP
      DBMS_OUTPUT.PUT_LINE(i || '*' || j || '=' || (i * j));
    END LOOP;
  END LOOP;
END;

DECLARE
  v_num VARCHAR2(10) := '';
BEGIN
  FOR i IN 1..4 LOOP
    v_num := v_num || i;
    DBMS_OUTPUT.PUT_LINE(v_num);
  END LOOP;
END;

BEGIN
  FOR i IN 1..20 LOOP
    CONTINUE WHEN MOD(i, 4) = 0;
    DBMS_OUTPUT.PUT_LINE(i);
  END LOOP;
END;

DECLARE
  s NUMBER := 0;
  i NUMBER := 1;
BEGIN
  LOOP
    s := s + i;
    DBMS_OUTPUT.PUT_LINE(i);
    i := i + 1;
    EXIT WHEN s > 100;
  END LOOP;
END;

BEGIN
  FOR i IN 1..20 LOOP
    DBMS_OUTPUT.PUT_LINE(i);
    EXIT WHEN MOD(i, 7) = 0;
  END LOOP;
END;

BEGIN
